import React, { useState } from 'react';
import Home from './pages/Home';
import LandingPage from './pages/LandingPage';

function App() {
  const [currentPage, setCurrentPage] = useState('landing');

  return (
    <div className="App">
      {currentPage === 'landing' ? (
        <LandingPage onStart={() => setCurrentPage('dashboard')} />
      ) : (
        <Home />
      )}
    </div>
  );
}

export default App;
